            for (int j = 0; j < i; j++)
                if (boxes[j][1] < boxes[i][1] && boxes[j][2] < boxes[i][2])
                    memo[i] = Math.max(memo[i], memo[j]);

            memo[i] += boxes[i][2];
            maxHeight = Math.max(maxHeight, memo[i]);
